class ImagePipeline:
    def generate_variant_set(self, base_prompt: str,
                             styles: list[str], sizes: list[str]) -> dict:
        """Generate styles × sizes matrix. Add rate-limit delay between calls."""
        results = {}
        for style in styles:
            style_results = []
            for size in sizes:
                prompt = f"{base_prompt}, {style}"
                result = self.service.generate(prompt=prompt, size=size)
                style_results.append({"size": size, "url": result["url"]})
                time.sleep(12)  # DALL-E tier-1: 5 img/min = 12s/img
            results[style] = style_results
        return results

    def a_b_test_images(self, concept: str, variations: list[str]) -> list[dict]:
        """Label variants A/B/C. Generate all before surfacing any."""
        results = []
        for i, variation in enumerate(variations):
            result = self.service.generate(prompt=f"{concept}, {variation}")
            results.append({"variant": chr(65 + i), "url": result["url"]})
        return results  # return complete set

class PromptTemplates:
    @staticmethod
    def product_photo(product: str, background: str = "white studio background",
                      lighting: str = "professional studio lighting") -> str:
        return f"{product}, {background}, {lighting}, product photography, high quality, 4K"

    @staticmethod
    def logo(concept: str, style: str = "minimalist", colors: str = "modern color palette") -> str:
        return f"{style} logo design, {concept}, {colors}, vector art, clean, professional"

    @staticmethod
    def social_media(content: str, platform: str = "instagram", mood: str = "vibrant") -> str:
        return f"{content}, {mood} mood, social media post, eye-catching, {platform} style"
